function pcRenderBars(e,t){let r="";for(const e in t){r+=`\n      <div class="pc-item">\n        <h3 class="pc-title">${e}</h3>\n        <div class="pc-progress">\n          <div class="pc-bar" data-size="${Number(t[e])||0}">\n            <span class="pc-percentage">0%</span>\n          </div>\n        </div>\n      </div>\n    `}e.innerHTML=r;const n=e.querySelectorAll(".pc-bar"),c=new IntersectionObserver(((e,t)=>{e.forEach((e=>{if(e.isIntersecting){const r=e.target,n=Math.max(0,Math.min(100,parseInt(r.dataset.size,10)||0)),c=r.querySelector(".pc-percentage");requestAnimationFrame((()=>{r.style.width=n+"%"}));let s=0;const a=2e3/Math.max(1,n),o=setInterval((()=>{s++,s>=n&&(s=n,clearInterval(o)),c.textContent=s+"%"}),a);t.unobserve(r)}}))}),{threshold:.8});n.forEach((e=>c.observe(e)))}document.querySelectorAll(".wrapper").forEach((e=>{const t=e.querySelector(".pc-progress-container"),r=e.querySelector("script[type='application/json']");if(t&&r){let e={};try{e=JSON.parse(r.textContent)}catch(e){console.error(e)}pcRenderBars(t,e)}}));
